from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

# Database connection parameters
DB_HOST = 'localhost'
DB_NAME = 'your_database_name'
DB_USER = 'your_username'
DB_PASS = 'your_password'

def get_db_connection():
    conn = psycopg2.connect(host=DB_HOST, database=DB_NAME, user=DB_USER, password=DB_PASS)
    return conn

@app.route('/query', methods=['GET'])
def query_data():
    table_name = request.args.get('table')
    columns = request.args.get('columns')
    filter_condition = request.args.get('filter')

    if not all([table_name, columns]):
        return jsonify({'error': 'Missing required parameters'}), 400

    # Constructing the SQL query dynamically
    sql_query = f"SELECT {columns} FROM {table_name}"
    params = []

    if filter_condition:
        sql_query += " WHERE "
        conditions = filter_condition.split(',')
        for condition in conditions:
            key, value = condition.split('=')
            sql_query += f"{key}=%s AND "
            params.append(value.strip())

    # Remove the last 'AND'
    sql_query = sql_query[:-5]

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute(sql_query, params)
    rows = cur.fetchall()
    columns = [desc[0] for desc in cur.description]
    cur.close()
    conn.close()

    return jsonify({'columns': columns, 'data': rows})

if __name__ == '__main__':
    app.run(debug=True)